                'agama' => '[]',
                'ages' => '[4,5,6,7,8,9,10]',
                'created_by' => 1,
                'creator' => 'kilo',
                'data' => '{"pages":[{"num":1,"text":"Di pinggir desa berdiri sebuah pohon mangga yang sangat besar dan rindang."},{"num":2,"text":"Setiap musim, pohon mangga berbuah lebat. Buahnya manis dan berwarna kuning cerah."},{"num":3,"text":"Burung-burung sering datang dan hinggap di dahan pohon mangga."},{"num":4,"text":"Pohon mangga senang melihat burung-burung makan buahnya dengan lahap."},{"num":5,"text":"Suatu hari, seekor monyet kecil datang dan meminta satu buah mangga."},{"num":6,"text":"Pohon mangga berkata, ambilah sebanyak yang kamu butuhkan, kawan."},{"num":7,"text":"Monyet kecil sangat senang. Ia memetik beberapa buah dan memakannya dengan gembira."},{"num":8,"text":"Lalu datang kelinci, kancil, dan tupai. Mereka semua meminta buah mangga."},{"num":9,"text":"Pohon mangga tidak pernah merasa sayang. Ia membagikan buahnya kepada semua hewan."},{"num":10,"text":"Beberapa anak desa juga datang bermain di bawah pohon mangga yang rindang."},{"num":11,"text":"Pohon mangga senang karena bisa memberikan tempat berteduh yang sejuk."},{"num":12,"text":"Suatu hari angin kencang merontokkan banyak buah mangga ke tanah."},{"num":13,"text":"Pohon mangga tidak sedih. Ia berkata, buah yang jatuh akan menjadi makanan untuk tanah."},{"num":14,"text":"Hewan-hewan dan anak-anak membantu mengumpulkan buah yang jatuh untuk dimakan bersama."},{"num":15,"text":"Pohon mangga mengajarkan bahwa berbagi dengan sesama membuat hidup lebih bermakna."}]}',
                'desc' => 'Pohon mangga yang rindang membagikan buahnya kepada burung, monyet, dan anak-anak desa',
                'image' => 'cover.png',
                'moral' => 'Berbagi dengan sesama membawa kebahagiaan. Ketika kita memberi, kita juga menerima kegembiraan dari orang-orang yang kita bantu.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '["berbagi", "peduli", "ramah"]',
                'slug' => 'pohon-mangga-yang-suka-berbagi',
