                'data' => '{"pages":[{"num":1,"text":"Sari adalah anak perempuan yang suka bermain di halaman rumahnya."},{"num":2,"text":"Setiap hari ia melihat banyak sampah plastik berserakan di jalan dekat rumah."},{"num":3,"text":"Sari merasa sedih melihat sampah yang membuat jalan menjadi kotor."},{"num":4,"text":"Suatu hari Sari melihat botol plastik bekas minuman di pinggir jalan."},{"num":5,"text":"Ia memungut botol itu dan membawanya pulang ke rumah."},{"num":6,"text":"Ibu Sari mengajarkan cara membersihkan dan menghias botol plastik."},{"num":7,"text":"Sari mewarnai botol plastik dengan cat warna-warni yang indah."},{"num":8,"text":"Botol plastik itu berubah menjadi tempat pensil yang cantik."},{"num":9,"text":"Sari semangat mencari lebih banyak sampah yang bisa didaur ulang."},{"num":10,"text":"Dari kardus bekas, Sari membuat kotak mainan bersama ayahnya."},{"num":11,"text":"Dari kain perca, ibu mengajarkan Sari membuat boneka tangan yang lucu."},{"num":12,"text":"Teman-teman Sari kagum melihat mainan-mainan yang dibuat dari barang bekas."},{"num":13,"text":"Sari mengajarkan teman-temannya cara membuat mainan dari sampah."},{"num":14,"text":"Sekarang jalan dekat rumah Sari bersih karena semua anak rajin memungut sampah."},{"num":15,"text":"Sari mengajarkan bahwa sampah bisa menjadi sesuatu yang berguna jika kita kreatif."}]}',
                'desc' => 'Sari, anak kreatif yang mengubah sampah menjadi mainan dan menginspirasi teman-temannya',
                'image' => 'cover.png',
